content.content:
1	/* AI-Agent Dashboard — Apple Design System (Claude Design v1에서 추출).
2	   외부 UUID @font-face 제거 → 시스템 폰트 스택(-apple-system→SF Pro) 사용. */
3	
4	/* ===========================================================================
5	   Apple Design System — global entry point.
6	   Consumers link THIS file. It is a manifest of @imports only.
7	   =========================================================================== */
8	
9	/* ===========================================================================
10	   FONTS — Apple Design System
11	   SF Pro is Apple's proprietary system font and cannot be embedded.
12	   Strategy (per the brand guide):
13	     1. The system stack (-apple-system, BlinkMacSystemFont) resolves to the
14	        REAL SF Pro Display / SF Pro Text on macOS / iOS / Safari.
15	     2. On non-Apple platforms, Inter (variable, Google Fonts) is the closest
16	        open-source substitute. Loaded below.
17	   ⚠️  SUBSTITUTION FLAG: Inter stands in for SF Pro off-Apple-devices.
18	   Provide the licensed SF Pro web fonts to make previews pixel-exact
19	   everywhere.
20	   =========================================================================== */
21	
22	/* Inter substitute tuning to approximate SF Pro:
23	   - feature ss03 gives Inter a rounder single-storey "a" (closer to SF Pro)
24	   - tracking is nudged tighter at display sizes in typography.css tokens     */
25	:root {
26	  --inter-features: "ss03" 1, "cv05" 1; /* @kind other */
27	}
28	
29	/* ===========================================================================
30	   COLORS — Apple Design System
31	   One blue accent. Light-dominant. Near-black ink, never pure black for text.
32	   Surface elevation comes from color change, not shadow.
33	   =========================================================================== */
34	
35	:root {
36	  /* --- Brand & Accent ---------------------------------------------------- */
37	  --color-primary: #0066cc;          /* Action Blue — every interactive element */
38	  --color-primary-focus: #0071e3;    /* Focus ring blue (slightly brighter)     */
39	  --color-primary-on-dark: #2997ff;  /* Sky Link Blue — links on dark surfaces  */
40	  --color-on-primary: #ffffff;       /* Text on Action Blue                     */
41	
42	  /* --- Surfaces ---------------------------------------------------------- */
43	  --color-canvas: #ffffff;                /* Pure white — dominant canvas       */
44	  --color-canvas-parchment: #f5f5f7;      /* Signature Apple off-white          */
45	  --color-surface-pearl: #fafafc;         /* Ghost-button fill (near white)     */
46	  --color-surface-tile-1: #272729;        /* Primary dark tile                  */
47	  --color-surface-tile-2: #2a2a2c;        /* Micro-step lighter dark tile       */
48	  --color-surface-tile-3: #252527;        /* Micro-step darker dark tile        */
49	  --color-surface-black: #000000;         /* True void — nav bar, video frames  */
50	  --color-surface-chip-translucent: #d2d2d7;        /* base hex of gray chip    */
51	  --color-surface-chip-translucent-64: rgba(210, 210, 215, 0.64); /* in use     */
52	
53	  /* --- Text -------------------------------------------------------------- */
54	  --color-ink: #1d1d1f;              /* Near-black — headlines, body, dark btn  */
55	  --color-body: #1d1d1f;             /* Same tone — one near-black for light    */
56	  --color-body-on-dark: #ffffff;     /* Text on dark tiles & nav                */
57	  --color-body-muted: #cccccc;       /* Secondary copy on dark tiles            */
58	  --color-ink-muted-80: #333333;     /* Body on pearl button surface            */
59	  --color-ink-muted-48: #7a7a7a;     /* Disabled text / legal fine-print        */
60	
61	  /* --- Hairlines & Borders ----------------------------------------------- */
62	  --color-divider-soft: #f0f0f0;     /* Soft ring on secondary buttons          */
63	  --color-divider-soft-alpha: rgba(0, 0, 0, 0.04); /* in-use alpha form         */
64	  --color-hairline: #e0e0e0;         /* 1px hairline on cards & chips           */
65	  --color-border-input: rgba(0, 0, 0, 0.08); /* input + soft-hairline border    */
66	}
67	
68	/* ===========================================================================
69	   TYPOGRAPHY — Apple Design System
70	   SF Pro Display (>=19px headlines) + SF Pro Text (body/UI).
71	   Negative tracking at display sizes = the "Apple tight" cadence.
72	   Weight ladder: 300 / 400 / 600 / 700.  500 is deliberately absent.
73	   NOTE: SF Pro is proprietary. The system stack resolves to real SF Pro on
74	   Apple devices; Inter is loaded as the cross-platform substitute.
75	   =========================================================================== */
76	
77	:root {
78	  /* --- Families ---------------------------------------------------------- */
79	  --font-display: -apple-system, BlinkMacSystemFont, "SF Pro Display", "Inter", system-ui, sans-serif;
80	  --font-text:    -apple-system, BlinkMacSystemFont, "SF Pro Text", "Inter", system-ui, sans-serif;
81	
82	  /* --- Weights ----------------------------------------------------------- */
83	  --weight-light: 300;     /* rare, airy reads only       */
84	  --weight-regular: 400;   /* default body                */
85	  --weight-semibold: 600;  /* headlines & strong emphasis */
86	  --weight-bold: 700;      /* sparing — taglines          */
87	
88	  /* --- Type ramp (size / weight / line-height / letter-spacing) ---------- */
89	  --type-hero-display-size: 56px;   --type-hero-display-weight: 600; --type-hero-display-lh: 1.07; --type-hero-display-ls: -0.28px;
90	  --type-display-lg-size: 40px;     --type-display-lg-weight: 600;  --type-display-lg-lh: 1.10;  --type-display-lg-ls: 0;
91	  --type-display-md-size: 34px;     --type-display-md-weight: 600;  --type-display-md-lh: 1.47;  --type-display-md-ls: -0.374px;
92	  --type-lead-size: 28px;           --type-lead-weight: 400;        --type-lead-lh: 1.14;        --type-lead-ls: 0.196px;
93	  --type-lead-airy-size: 24px;      --type-lead-airy-weight: 300;   --type-lead-airy-lh: 1.5;    --type-lead-airy-ls: 0;
94	  --type-tagline-size: 21px;        --type-tagline-weight: 600;     --type-tagline-lh: 1.19;     --type-tagline-ls: 0.231px;
95	  --type-body-strong-size: 17px;    --type-body-strong-weight: 600; --type-body-strong-lh: 1.24; --type-body-strong-ls: -0.374px;
96	  --type-body-size: 17px;           --type-body-weight: 400;        --type-body-lh: 1.47;        --type-body-ls: -0.374px;
97	  --type-dense-link-size: 17px;     --type-dense-link-weight: 400;  --type-dense-link-lh: 2.41;  --type-dense-link-ls: 0;
98	  --type-caption-size: 14px;        --type-caption-weight: 400;     --type-caption-lh: 1.43;     --type-caption-ls: -0.224px;
99	  --type-caption-strong-size: 14px; --type-caption-strong-weight: 600; --type-caption-strong-lh: 1.29; --type-caption-strong-ls: -0.224px;
100	  --type-button-large-size: 18px;   --type-button-large-weight: 300; --type-button-large-lh: 1.0; --type-button-large-ls: 0;
101	  --type-button-utility-size: 14px; --type-button-utility-weight: 400; --type-button-utility-lh: 1.29; --type-button-utility-ls: -0.224px;
102	  --type-fine-print-size: 12px;     --type-fine-print-weight: 400;  --type-fine-print-lh: 1.0;   --type-fine-print-ls: -0.12px;
103	  --type-micro-legal-size: 10px;    --type-micro-legal-weight: 400; --type-micro-legal-lh: 1.3;  --type-micro-legal-ls: -0.08px;
104	  --type-nav-link-size: 12px;       --type-nav-link-weight: 400;    --type-nav-link-lh: 1.0;     --type-nav-link-ls: -0.12px;
105	}
106	
107	/* --- Convenience utility classes (optional sugar over the tokens) -------- */
108	.t-hero-display { font-family: var(--font-display); font-size: var(--type-hero-display-size); font-weight: var(--type-hero-display-weight); line-height: var(--type-hero-display-lh); letter-spacing: var(--type-hero-display-ls); }
109	.t-display-lg  { font-family: var(--font-display); font-size: var(--type-display-lg-size); font-weight: var(--type-display-lg-weight); line-height: var(--type-display-lg-lh); letter-spacing: var(--type-display-lg-ls); }
110	.t-display-md  { font-family: var(--font-text); font-size: var(--type-display-md-size); font-weight: var(--type-display-md-weight); line-height: var(--type-display-md-lh); letter-spacing: var(--type-display-md-ls); }
111	.t-lead        { font-family: var(--font-text); font-size: var(--type-lead-size); font-weight: var(--type-lead-weight); line-height: var(--type-lead-lh); letter-spacing: var(--type-lead-ls); }
112	.t-lead-airy   { font-family: var(--font-text); font-size: var(--type-lead-airy-size); font-weight: var(--type-lead-airy-weight); line-height: var(--type-lead-airy-lh); letter-spacing: var(--type-lead-airy-ls); }
113	.t-tagline     { font-family: var(--font-text); font-size: var(--type-tagline-size); font-weight: var(--type-tagline-weight); line-height: var(--type-tagline-lh); letter-spacing: var(--type-tagline-ls); }
114	.t-body        { font-family: var(--font-text); font-size: var(--type-body-size); font-weight: var(--type-body-weight); line-height: var(--type-body-lh); letter-spacing: var(--type-body-ls); }
115	.t-body-strong { font-family: var(--font-text); font-size: var(--type-body-strong-size); font-weight: var(--type-body-strong-weight); line-height: var(--type-body-strong-lh); letter-spacing: var(--type-body-strong-ls); }
116	.t-caption     { font-family: var(--font-text); font-size: var(--type-caption-size); font-weight: var(--type-caption-weight); line-height: var(--type-caption-lh); letter-spacing: var(--type-caption-ls); }
117	.t-fine-print  { font-family: var(--font-text); font-size: var(--type-fine-print-size); font-weight: var(--type-fine-print-weight); line-height: var(--type-fine-print-lh); letter-spacing: var(--type-fine-print-ls); }
118	
119	/* ===========================================================================
120	   SPACING — Apple Design System
121	   Base unit 8px. Sub-base (2,4,5,6,7) for tight typographic adjustments;
122	   structural layout snaps to 8/12/16/20/24. Section padding = 80px.
123	   =========================================================================== */
124	
125	:root {
126	  --space-xxs: 4px;
127	  --space-xs: 8px;
128	  --space-sm: 12px;
129	  --space-md: 17px;      /* matches the 17px body rhythm */
130	  --space-lg: 24px;      /* card padding                 */
131	  --space-xl: 32px;
132	  --space-xxl: 48px;
133	  --space-section: 80px; /* vertical padding inside a product tile */
134	
135	  /* --- Containers -------------------------------------------------------- */
136	  --container-text: 980px;     /* text-heavy sections (environment) */
137	  --container-grid: 1440px;    /* product / utility grids           */
138	
139	  /* --- Grid gutters ------------------------------------------------------ */
140	  --gutter: 24px;
141	  --gutter-tight: 20px;
142	
143	  /* --- Button padding ---------------------------------------------------- */
144	  --btn-pad-y: 11px;   --btn-pad-x: 22px;   /* primary pill          */
145	  --btn-pad-y-util: 8px; --btn-pad-x-util: 15px; /* dark utility      */
146	  --btn-pad-y-large: 14px; --btn-pad-x-large: 28px; /* store hero     */
147	}
148	
149	/* ===========================================================================
150	   SHAPE & ELEVATION — Apple Design System
151	   Radius grammar is strict: sm / lg / pill, with rare md (Pearl Button).
152	   Exactly ONE drop shadow in the whole system — reserved for product imagery.
153	   =========================================================================== */
154	
155	:root {
156	  /* --- Border radius scale ----------------------------------------------- */
157	  --radius-none: 0px;     /* full-bleed product tiles            */
158	  --radius-xs: 5px;       /* inline link chips (rare)            */
159	  --radius-sm: 8px;       /* dark utility buttons, inline imagery */
160	  --radius-md: 11px;      /* Pearl Button capsules               */
161	  --radius-lg: 18px;      /* store + accessories utility cards   */
162	  --radius-pill: 9999px;  /* primary CTA, search, chips — the signature pill */
163	  --radius-full: 9999px;  /* circular control chips              */
164	
165	  /* --- Elevation --------------------------------------------------------- */
166	  /* The ONLY drop shadow in the system. Product renders resting on a surface. */
167	  --shadow-product: rgba(0, 0, 0, 0.22) 3px 5px 30px 0;
168	  /* Soft hairline "border-as-ring" tones */
169	  --border-hairline: 1px solid var(--color-hairline);
170	  --border-soft: 1px solid rgba(0, 0, 0, 0.08); /* @kind other */
171	
172	  /* --- Backdrop blur (frosted glass: sub-nav, sticky bar) ---------------- */
173	  --frost-bg: rgba(245, 245, 247, 0.8);          /* parchment @ 80%          */
174	  --frost-filter: saturate(180%) blur(20px); /* @kind other */
175	
176	  /* --- Motion ------------------------------------------------------------ */
177	  --press-scale: scale(0.95); /* @kind other */
178	  --ease-standard: cubic-bezier(0.4, 0, 0.2, 1); /* @kind other */
179	  --duration-fast: 120ms; /* @kind other */
180	}
181	
182	/* ===========================================================================
183	   AI-Agent Dashboard — built on the Apple Design System tokens.
184	   Light-dominant, one blue accent, hairline cards, no gradients, quiet ink.
185	   Two extra color AXES layered on top of the DS tokens:
186	     · tool axis   (Claude / Codex / Gemini)  — identity only
187	     · status axis (ok / warn / error / muted) — separate from tool color
188	   =========================================================================== */
189	
190	:root {
191	  /* tool identity (kept distinct from --color-primary action blue) */
192	  --tool-claude: #c2613f;   /* warm terracotta */
193	  --tool-codex:  #5b6573;   /* neutral slate   */
194	  --tool-gemini: #5e5ce6;   /* indigo          */
195	
196	  --tool-claude-soft: #f7ece7;
197	  --tool-codex-soft:  #eef0f2;
198	  --tool-gemini-soft: #ecebfb;
199	
200	  /* status axis */
201	  --st-ok:    #1d8a4e;  --st-ok-soft:    #e8f5ec;
202	  --st-warn:  #b25e00;  --st-warn-soft:  #fbf0e2;
203	  --st-error: #d70015;  --st-error-soft: #fdeaea;
204	  --st-muted: #86868b;  --st-muted-soft: #f0f0f2;
205	  --st-loss:  #d98324;  --st-loss-soft:  #fbeede;
206	
207	  --sidebar-w: 244px;
208	  --topbar-h: 73px;
209	}
210	
211	/* Dark mode — remap surfaces/ink to dark; status colors brighten on dark */
212	[data-theme="dark"] {
213	  --color-canvas: #1c1c1e;
214	  --color-canvas-parchment: #000000;
215	  --color-surface-pearl: #2c2c2e;
216	  --color-surface-tile-1: #0a0a0b;
217	  --color-ink: #f5f5f7;
218	  --color-body: #f5f5f7;
219	  --color-body-muted: #98989d;
220	  --color-hairline: #38383a;
221	  --color-divider-soft: #2a2a2c;
222	  --color-border-input: rgba(255,255,255,0.14);
223	
224	  --st-muted: #98989d; --st-muted-soft: rgba(255,255,255,0.10);
225	  --st-ok: #30d158;    --st-ok-soft: rgba(48,209,88,0.16);
226	  --st-warn: #ff9f0a;  --st-warn-soft: rgba(255,159,10,0.16);
227	  --st-loss: #ff9f0a;  --st-loss-soft: rgba(255,159,10,0.16);
228	  --st-error: #ff453a; --st-error-soft: rgba(255,69,58,0.18);
229	
230	  --tool-claude-soft: rgba(194,97,63,0.24);
231	  --tool-codex-soft:  rgba(150,160,175,0.20);
232	  --tool-gemini-soft: rgba(110,108,240,0.26);
233	
234	  --frost-bg: rgba(20,20,22,0.82);
235	}
236	[data-theme="dark"] .brand-mark { background: var(--color-primary); }
237	[data-theme="dark"] .stat.hero { border-color: var(--color-hairline); }
238	[data-theme="dark"] .nav-item.active,
239	[data-theme="dark"] .nav-item:hover,
240	[data-theme="dark"] .btn-ghost,
241	[data-theme="dark"] .tb-icon-btn,
242	[data-theme="dark"] .filter-pill { background: var(--color-surface-pearl); }
243	[data-theme="dark"] .nav-item.active .nav-count { background: #1c1c1e; }
244	
245	* { margin: 0; padding: 0; box-sizing: border-box; }
246	
247	html, body {
248	  height: 100%;
249	  background: var(--color-canvas-parchment);
250	  color: var(--color-ink);
251	  font-family: var(--font-text);
252	  font-size: var(--type-body-size);
253	  -webkit-font-smoothing: antialiased;
254	}
255	
256	button { font-family: inherit; cursor: pointer; border: none; background: none; color: inherit; }
257	::selection { background: rgba(0,102,204,0.16); }
258	
259	/* ---------- App shell ---------- */
260	.app {
261	  display: grid;
262	  grid-template-columns: var(--sidebar-w) 1fr;
263	  height: 100vh;
264	  overflow: hidden;
265	  background: var(--color-canvas-parchment);
266	  color: var(--color-ink);
267	}
268	
269	/* ---------- Sidebar ---------- */
270	.sidebar {
271	  background: var(--color-canvas);
272	  border-right: 1px solid var(--color-hairline);
273	  display: flex;
274	  flex-direction: column;
275	  padding: 22px 16px 18px;
276	}
277	.brand {
278	  display: flex; align-items: center; gap: 11px;
279	  padding: 4px 8px 22px;
280	}
281	.brand-mark {
282	  width: 34px; height: 34px; border-radius: 9px;
283	  background: var(--color-ink); color: #fff;
284	  display: grid; place-items: center; flex: none;
285	}
286	.brand-name { font-size: 17px; font-weight: 600; letter-spacing: -0.3px; }
287	.brand-sub { font-size: 11px; color: var(--st-muted); letter-spacing: -0.1px; margin-top: 1px; }
288	
289	.nav-group-label {
290	  font-size: 11px; font-weight: 600; letter-spacing: 0.02em;
291	  color: var(--st-muted); text-transform: uppercase;
292	  padding: 14px 10px 6px;
293	}
294	.nav {
295	  display: flex; flex-direction: column; gap: 2px;
296	}
297	.nav-item {
298	  display: flex; align-items: center; gap: 11px;
299	  padding: 9px 10px; border-radius: 9px;
300	  font-size: 14px; font-weight: 400; color: var(--color-ink);
301	  text-align: left; width: 100%;
302	  transition: background var(--duration-fast) var(--ease-standard);
303	}
304	.nav-item:hover { background: var(--color-canvas-parchment); }
305	.nav-item.active { background: var(--color-canvas-parchment); font-weight: 600; }
306	.nav-item.active .nav-ic { color: var(--color-primary); }
307	.nav-ic { color: var(--st-muted); flex: none; }
308	.nav-count {
309	  margin-left: auto; font-size: 12px; color: var(--st-muted);
310	  background: var(--color-canvas-parchment); border-radius: 9999px;
311	  padding: 1px 8px; font-variant-numeric: tabular-nums;
312	}
313	.nav-item.active .nav-count { background: #fff; }
314	
315	.sidebar-foot { margin-top: auto; padding: 12px 10px 0; }
316	.server-row { display: flex; align-items: center; gap: 8px; font-size: 12px; color: var(--color-ink); }
317	.server-dot { width: 8px; height: 8px; border-radius: 50%; background: var(--st-ok); flex: none; box-shadow: 0 0 0 3px var(--st-ok-soft); }
318	.local-badge {
319	  display: inline-flex; align-items: center; gap: 6px;
320	  margin-top: 10px; font-size: 11px; color: var(--st-muted);
321	}
322	
323	/* ---------- Main ---------- */
324	.main { display: flex; flex-direction: column; overflow: hidden; min-width: 0; }
325	
326	.topbar {
327	  height: var(--topbar-h); flex: none;
328	  display: flex; align-items: center; gap: 16px;
329	  padding: 0 32px;
330	  background: var(--frost-bg);
331	  -webkit-backdrop-filter: var(--frost-filter); backdrop-filter: var(--frost-filter);
332	  border-bottom: 1px solid var(--color-hairline);
333	}
334	.topbar-titles { min-width: 0; }
335	.topbar-title { font-size: 19px; font-weight: 600; letter-spacing: -0.3px; }
336	.topbar-sub { font-size: 12px; color: var(--st-muted); margin-top: 1px; }
337	.topbar-spacer { flex: 1; }
338	
339	.tb-icon-btn {
340	  width: 38px; height: 38px; border-radius: 50%; flex: none;
341	  display: grid; place-items: center; color: var(--color-ink);
342	  background: var(--color-canvas); border: 1px solid var(--color-hairline);
343	  transition: background var(--duration-fast);
344	}
345	.tb-icon-btn:hover { background: var(--color-canvas-parchment); }
346	.tb-avatar {
347	  display: flex; align-items: center; gap: 10px; padding-left: 6px;
348	}
349	.tb-ava-img {
350	  width: 38px; height: 38px; border-radius: 50%; flex: none;
351	  background: var(--color-surface-tile-1); color: #fff;
352	  display: grid; place-items: center; font-size: 14px; font-weight: 600;
353	}
354	.tb-ava-name { font-size: 13px; font-weight: 600; line-height: 1.2; }
355	.tb-ava-sub { font-size: 11px; color: var(--st-muted); }
356	
357	.search {
358	  display: flex; align-items: center; gap: 8px;
359	  height: 38px; padding: 0 14px;
360	  background: var(--color-canvas-parchment);
361	  border: 1px solid var(--color-border-input);
362	  border-radius: var(--radius-pill);
363	  color: var(--st-muted); min-width: 220px;
364	}
365	.search input {
366	  border: none; background: none; outline: none;
367	  font-size: 14px; color: var(--color-ink); width: 100%;
368	  font-family: inherit;
369	}
370	.search input::placeholder { color: var(--st-muted); }
371	
372	.btn {
373	  display: inline-flex; align-items: center; gap: 7px;
374	  height: 38px; padding: 0 16px; border-radius: var(--radius-pill);
375	  font-size: 14px; font-weight: 400; letter-spacing: -0.2px;
376	  transition: transform var(--duration-fast) var(--ease-standard), background var(--duration-fast) var(--ease-standard);
377	  white-space: nowrap;
378	}
379	.btn:active { transform: var(--press-scale); }
380	.btn-primary { background: var(--color-primary); color: #fff; }
381	.btn-secondary { background: transparent; color: var(--color-primary); border: 1px solid color-mix(in srgb, var(--color-primary) 35%, transparent); }
382	.btn-ghost { background: var(--color-canvas); color: var(--color-ink); border: 1px solid var(--color-hairline); }
383	.btn-ghost:hover { background: var(--color-canvas-parchment); }
384	.btn-sm { height: 32px; padding: 0 13px; font-size: 13px; }
385	.btn-danger { background: var(--st-error); color: #fff; }
386	
387	/* ---------- Content scroll ---------- */
388	.content { overflow-y: auto; padding: 28px 32px 56px; }
389	.content-inner { max-width: 1280px; margin: 0 auto; }
390	
391	.section-head {
392	  display: flex; align-items: baseline; gap: 10px; margin: 30px 2px 14px;
393	}
