/* Dark mode — remap surfaces/ink to dark; status colors brighten on dark */
[data-theme="dark"] {
  --color-canvas: #1c1c1e;
  --color-canvas-parchment: #000000;
  --color-surface-pearl: #2c2c2e;
  --color-surface-tile-1: #0a0a0b;
  --color-ink: #f5f5f7;
  --color-body: #f5f5f7;
  --color-body-muted: #98989d;
  --color-hairline: #38383a;
  --color-divider-soft: #2a2a2c;
  --color-border-input: rgba(255,255,255,0.14);

  --st-muted: #98989d; --st-muted-soft: rgba(255,255,255,0.10);
  --st-ok: #30d158;    --st-ok-soft: rgba(48,209,88,0.16);
  --st-warn: #ff9f0a;  --st-warn-soft: rgba(255,159,10,0.16);
  --st-loss: #ff9f0a;  --st-loss-soft: rgba(255,159,10,0.16);
  --st-error: #ff453a; --st-error-soft: rgba(255,69,58,0.18);

  --tool-claude-soft: rgba(194,97,63,0.24);
  --tool-codex-soft:  rgba(150,160,175,0.20);
  --tool-gemini-soft: rgba(110,108,240,0.26);

  --frost-bg: rgba(20,20,22,0.82);
}
[data-theme="dark"] .brand-mark { background: var(--color-primary); }
[data-theme="dark"] .stat.hero { border-color: var(--color-hairline); }
[data-theme="dark"] .nav-item.active,
[data-theme="dark"] .nav-item:hover,
[data-theme="dark"] .btn-ghost,
[data-theme="dark"] .tb-icon-btn,
[data-theme="dark"] .filter-pill { background: var(--color-surface-pearl); }
