input.new_string:
/* ---------- App shell ---------- */
/* 반응형 3단 레이아웃:
   · ≥1024px(넓음): 세로 사이드바 + 본문. 사이드바 접기 지원(.sidebar-collapsed).
   · <1024px(중간/좁음): 사이드바 숨김 + 상단 가로 메뉴(.topnav).            */
.app {
  display: grid;
  grid-template-columns: var(--sidebar-w) 1fr;
  grid-template-rows: 1fr;
  grid-template-areas: "sidebar main";
  height: 100vh;
  overflow: hidden;
  background: var(--color-canvas-parchment);
  color: var(--color-ink);
}
.app.sidebar-collapsed { grid-template-columns: var(--sidebar-w-collapsed) 1fr; }
.sidebar { grid-area: sidebar; }
.main { grid-area: main; }
/* 상단 가로 메뉴는 넓은 화면에선 숨김(사이드바 사용). */
.topnav { display: none; }

/* ---------- Sidebar ---------- */
.sidebar {
  background: var(--color-canvas);
  border-right: 1px solid var(--color-hairline);
  display: flex;
  flex-direction: column;
  padding: 22px 16px 18px;
  min-width: 0; overflow: hidden;
}
.brand {
  display: flex; align-items: center; gap: 11px;
  padding: 4px 8px 22px;
}
.brand-titles { min-width: 0; }
/* 사이드바 접기 버튼(브랜드 우측). 접힘/펼침 동일 버튼. */
.sidebar-toggle {
  margin-left: auto; flex: none;
  width: 26px; height: 26px; border-radius: 7px;
  display: grid; place-items: center; font-size: 15px; line-height: 1;
  color: var(--st-muted); border: 1px solid var(--color-hairline); background: var(--color-canvas);
  transition: background var(--duration-fast), transform var(--duration-fast) var(--ease-standard);
}
.sidebar-toggle:hover { background: var(--color-canvas-parchment); }

/* ----- 접힌 사이드바(아이콘만) ----- */
.app.sidebar-collapsed .brand-titles,
.app.sidebar-collapsed .nav-label,
.app.sidebar-collapsed .nav-group-label,
.app.sidebar-collapsed .nav-count,
.app.sidebar-collapsed .sidebar-foot .nav-label { display: none; }
.app.sidebar-collapsed .sidebar { padding: 22px 10px 18px; align-items: center; }
.app.sidebar-collapsed .brand { padding: 4px 0 20px; justify-content: center; }
.app.sidebar-collapsed .sidebar-toggle { margin-left: 0; transform: rotate(180deg); }
.app.sidebar-collapsed .nav-item { justify-content: center; padding: 9px 0; width: 42px; }
.app.sidebar-collapsed .server-row,
.app.sidebar-collapsed .local-badge { justify-content: center; }

