@media (max-width: 1080px) {
  .stat-grid { grid-template-columns: repeat(2, 1fr); }
  .row-2 { grid-template-columns: 1fr; }
  .bento { grid-template-columns: 1fr; }
  .bento-3 { grid-template-columns: 1fr; }
  .overlay-grid { grid-template-columns: 1fr; }
}

/* ═══════════ 반응형 3단: <1024px → 사이드바 숨김 + 상단 가로 메뉴 ═══════════ */
/* 세로 사이드바를 감추고, .topnav(가로 스크롤 탭 바)를 상단에 노출한다.
   .app는 1열·2행(topnav / main)으로 재구성. JS 개입 없이 CSS만으로 전환. */
@media (max-width: 1023.98px) {
  .app,
  .app.sidebar-collapsed {
    grid-template-columns: 1fr;
    grid-template-rows: var(--topnav-h) 1fr;
    grid-template-areas: "topnav" "main";
  }
  .sidebar { display: none; }         /* 좁은 화면에선 세로 사이드바 미사용 */
  .topnav {
    grid-area: topnav; display: flex; align-items: center; gap: 12px;
    padding: 0 16px; min-width: 0;
    background: var(--frost-bg);
    -webkit-backdrop-filter: var(--frost-filter); backdrop-filter: var(--frost-filter);
    border-bottom: 1px solid var(--color-hairline);
  }
  .topnav-brand {
    flex: none; width: 30px; height: 30px; border-radius: 8px;
    background: var(--color-ink); color: #fff;
    display: grid; place-items: center; font-size: 11px; font-weight: 700; letter-spacing: -0.3px;
  }
  /* 뷰 탭: 가로 스크롤 허용(항목이 많아도 한 줄, 스크롤바 숨김). */
  .topnav-tabs {
    display: flex; align-items: center; gap: 4px; min-width: 0;
    overflow-x: auto; scrollbar-width: none; -webkit-overflow-scrolling: touch;
  }
  .topnav-tabs::-webkit-scrollbar { display: none; }
  .topnav-tab {
    flex: none; height: 34px; padding: 0 13px; border-radius: 9999px;
    font-size: 13px; font-weight: 400; color: var(--color-ink); white-space: nowrap;
    border: 1px solid transparent;
    transition: background var(--duration-fast), color var(--duration-fast);
  }
  .topnav-tab:hover { background: var(--color-canvas); }
  .topnav-tab.active { background: var(--color-ink); color: #fff; font-weight: 600; }

  .topbar { padding: 0 16px; }
  .content { padding: 20px 16px 48px; }
}

@media (max-width: 560px) {
  .stat-grid { grid-template-columns: 1fr; }
  .topbar-sub { display: none; }      /* 아주 좁으면 부제 숨김(제목만) */
}

